import React, { createContext, useContext, useState, useEffect } from 'react';
import toast from 'react-hot-toast';
import { useAuth } from './AuthContext';
import { cartService } from '../services/cartService';
import { cartItemService } from '../services/cartItemService';
import {
  getCartId,
  getCartItemId,
  getItemQuantity,
  getProductId,
  getProductName,
  getProductPrice,
  getUserId,
  normalizeList,
} from '../utils/entityAdapters';

const CartContext = createContext();
export const useCart = () => useContext(CartContext);

export const CartProvider = ({ children }) => {
  const { user } = useAuth();
  const [cart, setCart] = useState(null);
  const [cartItems, setCartItems] = useState([]);
  const [cartCount, setCartCount] = useState(0);
  const getCartCacheKey = () => {
    const userId = getUserId(user);
    return userId ? `freshmart_cart_${userId}` : null;
  };

  const syncCartState = (nextCart, nextItems) => {
    setCart(nextCart);
    setCartItems(nextItems);
    setCartCount(nextItems.reduce((sum, item) => sum + getItemQuantity(item), 0));
    const key = getCartCacheKey();
    if (key) {
      localStorage.setItem(key, JSON.stringify({ cart: nextCart, items: nextItems }));
    }
  };

  useEffect(() => {
    if (user) {
      const key = getCartCacheKey();
      if (key) {
        const cached = localStorage.getItem(key);
        if (cached) {
          try {
            const parsed = JSON.parse(cached);
            syncCartState(parsed.cart || null, normalizeList(parsed.items || []));
          } catch {
            localStorage.removeItem(key);
          }
        }
      }
      loadCart();
    } else {
      setCart(null);
      setCartItems([]);
      setCartCount(0);
    }
  }, [user]);

  const loadCart = async (options = {}) => {
    const fallbackItems = normalizeList(options.fallbackItems || []);
    try {
      const userId = getUserId(user);
      if (!userId) return false;

      let cartResponse;
      try {
        cartResponse = await cartService.getCartByUserId(userId);
      } catch {
        const allCarts = normalizeList(await cartService.getAllCarts());
        cartResponse = allCarts.find((c) => String(getUserId(c)) === String(userId)) || null;
      }

      const resolvedCart = Array.isArray(cartResponse) ? cartResponse[0] : (normalizeList(cartResponse)[0] || cartResponse);
      const resolvedCartId = getCartId(resolvedCart);
      if (!resolvedCartId) {
        setCart(null);
        setCartItems([]);
        setCartCount(0);
        return false;
      }

      setCart(resolvedCart);
      let items = normalizeList(resolvedCart?.cartItems || resolvedCart?.cartItemList || []);
      if (items.length === 0) {
        const itemsResponse = await cartItemService.getItemsByCartId(resolvedCartId);
        items = normalizeList(itemsResponse);
      }
      if (items.length === 0 && fallbackItems.length > 0) {
        items = fallbackItems;
      }
      syncCartState(resolvedCart, items);
      return true;
    } catch {
      const key = getCartCacheKey();
      if (!key) {
        setCart(null);
        setCartItems([]);
        setCartCount(0);
      }
      return false;
    }
  };

  const addToCart = async (product) => {
    if (!user) {
      toast.error('Please login to add items');
      return;
    }

    let synced = false;
    try {
      let activeCart = cart;
      const userId = getUserId(user);

      if (!getCartId(activeCart)) {
        activeCart = await cartService.createCart({
          user: { userId },
          totalAmount: 0,
          discount: 0,
        });
        setCart(activeCart);
      }

      const productId = getProductId(product);
      const existing = cartItems.find((item) => getProductId(item) === productId);
      let optimisticItems = [...cartItems];
      if (existing) {
        optimisticItems = optimisticItems.map((item) =>
          String(getProductId(item)) === String(productId)
            ? { ...item, quantity: getItemQuantity(item) + 1, qty: getItemQuantity(item) + 1 }
            : item
        );
      } else {
        optimisticItems.push({
          id: `local-${Date.now()}`,
          productId,
          product_id: productId,
          productName: getProductName(product),
          category: product?.category,
          quantity: 1,
          qty: 1,
          price: getProductPrice(product),
          unitPrice: getProductPrice(product),
        });
      }
      syncCartState(activeCart, optimisticItems);

      if (existing) {
        const id = getCartItemId(existing);
        await cartItemService.updateCartItem(id, {
          ...existing,
          qty: getItemQuantity(existing) + 1,
          quantity: getItemQuantity(existing) + 1,
        });
      } else {
        await cartItemService.addCartItem({
          cartId: getCartId(activeCart),
          cart_id: getCartId(activeCart),
          productId,
          product_id: productId,
          quantity: 1,
          qty: 1,
          price: getProductPrice(product),
          unitPrice: getProductPrice(product),
          cart: { cartId: getCartId(activeCart) },
          product: { productId },
        });
      }
      synced = true;

      const loaded = await loadCart({ fallbackItems: optimisticItems });
      if (!loaded) {
        syncCartState(activeCart, optimisticItems);
      }
      toast.success(`${getProductName(product)} added to cart`);
    } catch {
      if (cartItems.length >= 0) {
        toast.success(`${getProductName(product)} added locally`);
      } else {
        toast.error('Failed to add item');
      }
    } finally {
      if (!synced) {
        // Keep optimistic state even when backend add API fails.
        const key = getCartCacheKey();
        if (key && !localStorage.getItem(key)) {
          localStorage.setItem(key, JSON.stringify({ cart, items: cartItems }));
        }
      }
    }
  };

  const removeFromCart = async (cartItemId) => {
    const nextItems = cartItems.filter((item) => String(getCartItemId(item)) !== String(cartItemId));
    syncCartState(cart, nextItems);
    try {
      await cartItemService.removeCartItem(cartItemId);
      await loadCart();
      toast.success('Item removed');
    } catch {
      toast.success('Item removed locally');
    }
  };

  return (
    <CartContext.Provider value={{ cart, cartItems, cartCount, addToCart, removeFromCart, loadCart }}>
      {children}
    </CartContext.Provider>
  );
};
